head.script:
//전역변수
scwin.memJson = $c.data.getMemInfo(); // 로그인 정보를 가져온다.
scwin.privAdmin = scwin.memJson.privAdmin; // ADMIN 권한 CHK : 'T' : ADMIN , 'F': ADMIN 아님

scwin.vLoginCoCd = $c.gus.cfIsNull(scwin.memJson.coCd) ? '' : scwin.memJson.coCd; // 소속 자회사
scwin.vLoginCoClsCd = $c.gus.cfIsNull(scwin.memJson.coClsCd) ? '' : scwin.memJson.coClsCd; // 회계_회사구분('CO035' : 0:동부 EXPRESS)
scwin.vUserHomeClsCd = scwin.memJson.userHomeClsCd; // 사용자소속구분코드
scwin.isSubCompany = false;

scwin.txtCoCd = "";
scwin.txtCoClsCd = "";
scwin.isStart = false;

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {

};

//-------------------------------------------------------------------------
// UDC 로딩 완료 후
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    scwin.f_setCompanyInfo();
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function() {
    let ret = await $c.gus.cfValidate([ed_coCd, ica_closeYm]);
    if (!ret) {
        return false;
    }

    const params = {
        closeDd: "00", 
        mgntNo: "0",
        wrkNo: ACConstants.CLOSE_WITHHOLD,
        coClsCd: scwin.txtCoClsCd
    };

    //데이터셋에 정보설정
    dma_search.setJSON(params);

    $c.sbm.execute(sbm_search);
};

//-------------------------------------------------------------------------
// 자회사 회계 시스템 추가에 따른 설정
//-------------------------------------------------------------------------
scwin.f_setCompanyInfo = function() {
    // 사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를 '동부 EXPRESS'로 Default set
    if (scwin.vUserHomeClsCd !== ACConstants.SUBSIDIARY_USER_HOME_CLS_CD) {
        scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
        scwin.vLoginCoClsCd = ACConstants.CO_CLS_CD_DONGBU;
    }
    scwin.isStart=true;
    ed_coCd.setValue(scwin.vLoginCoCd);
    scwin.f_PopUpCompanyInfo('T');
};

//-------------------------------------------------------------------------
// 원천세신고내역집계
//-------------------------------------------------------------------------
scwin.f_Withhold = async function() {
    let ret = await $c.gus.cfValidate([ed_coCd, ica_closeYm]);
    if (!ret) {
        return false;
    }

    // 마감체크
    let jobCloseRet = await scwin.f_JobCloseYN();
    if (!jobCloseRet) {
        return false;
    }

    if (await $c.win.confirm($c.data.getMessage(MSG_CM_CRM_010, ["원천세신고내역집계"]))) {
        dma_search.set("coClsCd", scwin.txtCoClsCd);
        $c.sbm.execute(sbm_withhold);
    }
};

//-------------------------------------------------------------------------
// 삭제
//-------------------------------------------------------------------------
scwin.f_Delete = async function() {
    let ret = await $c.gus.cfValidate([ica_closeYm]);
    if (!ret) {
        return false;
    }

    // 마감체크
    let jobCloseRet = await scwin.f_JobCloseYN();
    if (!jobCloseRet) {
        return false;
    }

    if (await $c.win.confirm($c.data.getMessage(MSG_CM_CRM_008, ["원천세신고내역집계"]))) {
        dma_search.set("coClsCd", scwin.txtCoClsCd);
        $c.sbm.execute(sbm_withholdDelete);
    }
};

//-------------------------------------------------------------------------
// 마감체크
//-------------------------------------------------------------------------
scwin.f_JobCloseYN = async function() {
    // cfJobCloseYN(마감요청구분,마감년월,마감일,작업번호,관리번호,리턴구분);
    let isClose = await udc_closeYn.cfJobCloseYN("CUR", ica_closeYm.getValue().trim(), "00", ACConstants.CLOSE_WITHHOLD, "0", "", "", ed_coCd.getValue());
    if (isClose === "0") {
        await $c.win.alert("마감중입니다.");
        return false;
    } else if (isClose === "2") {
        await $c.win.alert("마감완료가 되었습니다");
        return false;
    } else {
        return true;
    }
};

//-------------------------------------------------------------------------
// 회사 입력 팝업
//-------------------------------------------------------------------------
scwin.f_PopUpCompanyInfo = async function(pWinCloseTF) {
    udc_dongbuGroupCompanyInfo.cfCommonPopUp(scwin.udc_dongbuGroupCompanyInfo_callBackFunc, ed_coCd.getValue(), ed_coNm.getValue(), pWinCloseTF, null, null, null, null, null, null, null, null, null);
};

scwin.udc_dongbuGroupCompanyInfo_callBackFunc = function(rtnList) {
    if (rtnList !== null) {
        if (rtnList[0] === "N/A") return;

        ed_coCd.setValue(rtnList[0]);
        ed_coNm.setValue(rtnList[5]);
        if (!ed_coCd.options) ed_coCd.options = {};
        ed_coCd.options.hidVal = rtnList[0];
        scwin.txtCoClsCd = rtnList[1];
        scwin.txtCoCd = rtnList[0];
    } else {
        ed_coCd.setValue("");
        ed_coNm.setValue("");
        if (!ed_coCd.options) ed_coCd.options = {};
        ed_coCd.options.hidVal = "";
        scwin.txtCoClsCd = "";
        scwin.txtCoCd = "";
    }

    if (scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU) {  // 자회사 회계 시스템 
        scwin.isSubCompany = true;
    } else {
        scwin.isSubCompany = false;
    }
    if(scwin.isStart){
        if (scwin.privAdmin === 'T' || !scwin.isSubCompany) {   // ADMIN 권한이 있는 경우, 동부 EXPRESS 인 경우 
            $c.gus.cfEnableObjects([ed_coCd, ed_coNm, btn_company]);
        } else {
            $c.gus.cfDisableObjects([ed_coCd, ed_coNm, btn_company]);
        }
    }
    scwin.isStart=false;
};

scwin.sbm_search_submitdone = async function (e) {
    rowCnt = ds_withhold.getRowCount();
    gr_prepay.setFocusedCell(0, 0);
    totalRows.setValue(rowCnt);
    if( rowCnt == 0 ){
		await $c.win.alert(MSG_CM_WRN_002);
	}  
};


scwin.sbm_withhold_submitdone = async function (e) {
    if(e.responseJSON.resultDataSet[0].Code != -1){
        await $c.win.alert("성공적으로 처리되었습니다");
        ds_withhold.reform();
        scwin.f_Retrieve();
    }
};

scwin.sbm_withholdDelete_submitdone = async function (e) {
    if(e.responseJSON.resultDataSet[0].Code != -1){
        await $c.win.alert("성공적으로 삭제되었습니다");
        ds_withhold.reform();
        scwin.f_Retrieve();
    }
};

scwin.udc_dongbuGroupCompanyInfo_onblurCodeEvent = function (e) {
    ed_coNm.setValue("");
    if (ed_coCd.getValue() != ""){
        scwin.f_PopUpCompanyInfo('T');
    }
    else{
        ed_coNm.setValue("");
    }
};

scwin.btn_retrieve_onclick = function (e) {
    scwin.f_Retrieve();
};

scwin.btn_evid_onclick = function (e) {
    scwin.f_Withhold(); 
};

scwin.btn_delete_onclick = function (e) {
    scwin.f_Delete();
};

scwin.udc_dongbuGroupCompanyInfo_onclickEvent = function (e) {
    scwin.f_PopUpCompanyInfo('F');
};
